4	#include "po/argument_parser.h"
5	#include "common/defines.h"
6	#include "common/spdlog.h"
7	#include "system/winapi.h"
8	#include <cstdio>
9	
10	namespace WasmEdge {
11	namespace PO {
12	
13	cxx20::expected<bool, Error> ArgumentParser::SubCommandDescriptor::parse(
14	    std::FILE *Out, Span<const char *> ProgramNamePrefix, int Argc,
15	    const char *Argv[], int ArgP, const bool &VersionOpt) noexcept {
16	  ProgramNames.reserve(ProgramNamePrefix.size() + 1);
17	  ProgramNames.assign(ProgramNamePrefix.begin(), ProgramNamePrefix.end());
18	  if (ArgP < Argc) {
19	    ProgramNames.push_back(Argv[ArgP]);
20	  }
21	  ArgumentDescriptor *CurrentDesc = nullptr;
22	  bool FirstNonOption = true;
23	  bool Escaped = false;
24	  auto PositionalIter = PositionalList.cbegin();
25	  for (int ArgI = ArgP + 1; ArgI < Argc; ++ArgI) {
26	    std::string_view Arg = Argv[ArgI];
27	    if (!Escaped && Arg.size() >= 2 && Arg[0] == '-') {
28	      if (Arg[1] == '-') {
29	        if (Arg.size() == 2) {
30	          Escaped = true;
31	        } else {
32	          // long option
33	          if (CurrentDesc && CurrentDesc->nargs() == 0) {
34	            CurrentDesc->default_value();
35	          }
36	          if (auto Res = consume_long_option_with_argument(Arg); !Res) {
37	            return cxx20::unexpected(Res.error());
38	          } else {
39	            CurrentDesc = *Res;
40	          }
41	        }
42	      } else {
43	        // short options
44	        if (CurrentDesc && CurrentDesc->nargs() == 0) {
45	          CurrentDesc->default_value();
46	        }
47	        if (auto Res = consume_short_options(Arg); !Res) {
48	          return cxx20::unexpected(Res.error());
49	        } else {
50	          CurrentDesc = *Res;
51	        }
52	      }
53	    } else if (!Escaped && CurrentDesc) {
54	      consume_argument(*CurrentDesc, Arg);
55	      CurrentDesc = nullptr;
56	    } else {
57	      // no more options
58	      if (FirstNonOption) {
59	        FirstNonOption = false;
60	        if (!SubCommandMap.empty()) {
61	          if (auto Iter = SubCommandMap.find(Arg);
62	              Iter != SubCommandMap.end()) {
63	            auto &Child = this[Iter->second];
64	            Child.SC->select();
65	            return Child.parse(Out, ProgramNames, Argc, Argv, ArgI, VersionOpt);
66	          }
67	        }
68	      }
69	      Escaped = true;
70	      if (CurrentDesc) {
71	        if (auto Res = consume_argument(*CurrentDesc, Arg); !Res) {
72	          return cxx20::unexpected(Res.error());
73	        } else {
74	          CurrentDesc = *Res;
75	        }
76	      } else {
77	        if (PositionalIter == PositionalList.cend()) {
78	          return cxx20::unexpected<Error>(
79	              std::in_place, ErrCode::InvalidArgument,
80	              "positional argument exceeds maximum consuming."s);
81	        }
82	        if (auto Res =
83	                consume_argument(ArgumentDescriptors[*PositionalIter], Arg);
84	            !Res) {
85	          return cxx20::unexpected(Res.error());
86	        } else {
87	          CurrentDesc = *Res;
88	        }
89	        ++PositionalIter;
90	      }
91	    }
92	  }
93	  if (CurrentDesc && CurrentDesc->nargs() == 0) {
94	    CurrentDesc->default_value();
95	  }
96	
97	  if (VersionOpt) {
98	    return true;
99	  }
100	  if (!HelpOpt->value()) {
101	    for (const auto &Desc : ArgumentDescriptors) {
102	      if (Desc.nargs() < Desc.min_nargs()) {
103	        help(Out);
104	        return false;
105	      }
106	    }
107	  } else {
108	    help(Out);
109	    return true;
110	  }
111	  return true;
112	}
113	
114	void ArgumentParser::SubCommandDescriptor::usage(
115	    std::FILE *Out) const noexcept {
116	  fmt::print(Out, "{}USAGE{}\n"sv, YELLOW_COLOR, RESET_COLOR);
117	  for (const char *Part : ProgramNames) {
118	    fmt::print(Out, "\t{}"sv, Part);
119	  }
120	  if (!SubCommandList.empty()) {
121	    fmt::print(Out, " [SUBCOMMANDS]"sv);
122	  }
123	  if (!NonpositionalList.empty()) {
124	    fmt::print(Out, " [OPTIONS]"sv);
125	  }
126	  bool First = true;
127	  for (const auto &Index : PositionalList) {
128	    const auto &Desc = ArgumentDescriptors[Index];
129	    if (Desc.hidden()) {
130	      continue;
131	    }
132	
133	    if (First) {
134	      fmt::print(Out, " [--]"sv);
135	      First = false;
136	    }
137	
138	    const bool Optional = (Desc.min_nargs() == 0);
139	    fmt::print(Out, " "sv);
140	    if (Optional) {
141	      fmt::print(Out, "["sv);
142	    }
143	    switch (ArgumentDescriptors[Index].max_nargs()) {
144	    case 0:
145	      break;
146	    case 1:
147	      fmt::print(Out, "{}"sv, Desc.meta());
148	      break;
149	    default:
150	      fmt::print(Out, "{} ..."sv, Desc.meta());
151	      break;
152	    }
153	    if (Optional) {
154	      fmt::print(Out, "]"sv);
155	    }
156	  }
157	  fmt::print(Out, "\n"sv);
158	}
159	
160	void ArgumentParser::SubCommandDescriptor::help(std::FILE *Out) const noexcept {
161	// For enabling Windows PowerShell color support.
162	#if WASMEDGE_OS_WINDOWS && WINAPI_PARTITION_DESKTOP
163	  winapi::HANDLE_ OutputHandler =
164	      winapi::GetStdHandle(winapi::STD_OUTPUT_HANDLE_);
165	  if (OutputHandler != winapi::INVALID_HANDLE_VALUE_) {
166	    winapi::DWORD_ ConsoleMode = 0;
167	    if (winapi::GetConsoleMode(OutputHandler, &ConsoleMode)) {
168	      ConsoleMode |= winapi::ENABLE_VIRTUAL_TERMINAL_PROCESSING_;
169	      winapi::SetConsoleMode(OutputHandler, ConsoleMode);
170	    }
171	  }
172	#endif
173	
174	  usage(Out);
175	  const constexpr std::string_view kIndent = "\t"sv;
176	
177	  fmt::print(Out, "\n"sv);
178	  if (!SubCommandList.empty()) {
179	    fmt::print(Out, "{}SUBCOMMANDS{}\n"sv, YELLOW_COLOR, RESET_COLOR);
180	    for (const auto Offset : SubCommandList) {
181	      fmt::print(Out, "{}{}"sv, kIndent, GREEN_COLOR);
182	      bool First = true;
183	      for (const auto &Name : this[Offset].SubCommandNames) {
184	        if (!First) {
185	          fmt::print(Out, "|"sv);
186	        }
187	        fmt::print(Out, "{}"sv, Name);
188	        First = false;
189	      }
190	      fmt::print(Out, "{}\n"sv, RESET_COLOR);
191	      indent_output(Out, kIndent, 2, 80, this[Offset].SC->description());
192	      fmt::print(Out, "\n"sv);
193	    }
194	    fmt::print(Out, "\n"sv);
195	  }
196	
197	  fmt::print(Out, "{}OPTIONS{}\n"sv, YELLOW_COLOR, RESET_COLOR);
198	  for (const auto &Index : NonpositionalList) {
199	    const auto &Desc = ArgumentDescriptors[Index];
200	    if (Desc.hidden()) {
201	      continue;
202	    }
203	
204	    fmt::print(Out, "{}{}\n"sv, kIndent, GREEN_COLOR);
205	    bool First = true;
206	    for (const auto &Option : Desc.options()) {
207	      if (!First) {
208	        fmt::print(Out, "|"sv);
209	      }
210	      if (Option.size() == 1) {
211	        fmt::print(Out, "-{}"sv, Option);
212	      } else {
213	        fmt::print(Out, "--{}"sv, Option);
214	      }
215	      First = false;
216	    }
217	    fmt::print(Out, "{}\n"sv, RESET_COLOR);
218	    indent_output(Out, kIndent, 2, 80, Desc.description());
219	    fmt::print(Out, "\n"sv);
220	  }
221	}
222	
223	void ArgumentParser::SubCommandDescriptor::indent_output(
224	    std::FILE *Out, const std::string_view kIndent, std::size_t IndentCount,
225	    std::size_t ScreenWidth, std::string_view Desc) const noexcept {
226	  const std::size_t Width = ScreenWidth - kIndent.size() * IndentCount;
227	  while (Desc.size() > Width) {
228	    const std::size_t SpacePos = Desc.find_last_of(' ', Width);
229	    if (SpacePos != std::string_view::npos) {
230	      for (std::size_t I = 0; I < IndentCount; ++I) {
231	        fmt::print(Out, "{}"sv, kIndent);
232	      }
233	      fmt::print(Out, "{}\n"sv, Desc.substr(0, SpacePos));
234	      const std::size_t WordPos = Desc.find_first_not_of(' ', SpacePos);
235	      if (WordPos != std::string_view::npos) {
236	        Desc = Desc.substr(WordPos);
237	      } else {
238	        Desc = {};
239	      }
240	    }
241	  }
242	  if (!Desc.empty()) {
243	    for (std::size_t I = 0; I < IndentCount; ++I) {
244	      fmt::print(Out, "{}"sv, kIndent);
245	    }
246	    fmt::print(Out, "{}"sv, Desc);
247	  }
248	}
249	
250	cxx20::expected<ArgumentParser::ArgumentDescriptor *, Error>
251	ArgumentParser::SubCommandDescriptor::consume_short_options(
252	    std::string_view Arg) noexcept {
